import{_ as s,c as e,o as p,ag as n}from"./chunks/framework.ELrfyV9R.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/RookieRicardoR/status/2034793001864872440","created":"2026-04-01T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/学一个新领域，我现在的第一步是把它抓下来.md","filePath":"ai/bookmark/学一个新领域，我现在的第一步是把它抓下来.md","lastUpdated":1776945928000}'),t={name:"ai/bookmark/学一个新领域，我现在的第一步是把它抓下来.md"};function o(l,a,i,r,c,d){return p(),e("div",null,a[0]||(a[0]=[n(`<p>最近一直在看 Simon Willison 的文章。</p><p>他是 Django 框架的联合创始人，现在是 AI 工具链领域最活跃的独立开发者之一，博客 <a href="https://simonwillison.net/" target="_blank" rel="noreferrer">simonwillison.net</a> 上有超过十年的技术文章，内容覆盖 Python、SQLite、LLM 应用、数据工程……信息密度极高。</p><p>看着看着，我就想——能不能把他所有博客全部抓下来，做成一个私人知识库？以后想了解他对某个技术的看法，直接问 AI 就行，不用一篇一篇翻。</p><p>不光如此，这个思路可以推广到任何领域：找到某个方向最好的内容源，批量抓下来，做成你自己的领域知识库。</p><h2 id="一-遇到的问题" tabindex="-1">一：遇到的问题 <a class="header-anchor" href="#一-遇到的问题" aria-label="Permalink to &quot;一：遇到的问题&quot;">​</a></h2><p>我第一反应是直接告诉 OpenClaw 我的需求，让它帮我解决。</p><p>但是实测下来，<strong>单篇文章没问题，但批量抓取搞不定</strong>，它自己安装了一些开源工具做这事但是返回了很多无关的链接，所以它不具备直接做到「给我这个站点所有文章」的能力。</p><p>而我需要的是：</p><ol><li>先拿到 Simon 博客上所有文章的 URL 列表。</li><li>再逐篇把内容抓下来，转成干净的 Markdown。</li><li>最好能直接在 AI 对话里完成，不用写代码。</li></ol><p>后来发现了 <strong>XCrawl</strong> 这个工具，完美解决了这三个问题。</p><h2 id="二-xcrawl-是什么" tabindex="-1">二：XCrawl 是什么 <a class="header-anchor" href="#二-xcrawl-是什么" aria-label="Permalink to &quot;二：XCrawl 是什么&quot;">​</a></h2><p>简单说，XCrawl 是一个网页抓取 API 服务，提供四个核心能力：</p><p>1. <strong>Search</strong>：搜索引擎查询，返回结构化结果（标题、URL、摘要、排名）</p><p>2. <strong>Map</strong>：扫描一个站点，列出它所有的 URL</p><p>3. <strong>Scrape</strong>：抓取指定 URL 的页面内容，输出干净的 Markdown</p><p>4. <strong>Crawl</strong>：全站递归爬取，适合大规模批量抓取</p><p>而且它提供了 OpenClaw 的 Skill，意味着你可以直接在 OpenClaw 里用自然语言调用这些能力，不用写任何代码。</p><p>使用时只需要先去 <a href="https://www.xcrawl.com/?keyword=ut0qflxk" target="_blank" rel="noreferrer">https://www.xcrawl.com/?keyword=ut0qflxk</a> 注册拿到 Key，新账号有 1000 积分免费额度，然后把它的 Skill 文档链接 <a href="https://docs.xcrawl.com/zh/doc/developer-guides/openclaw/" target="_blank" rel="noreferrer">https://docs.xcrawl.com/zh/doc/developer-guides/openclaw/</a> 直接告诉 OpenClaw，然后龙虾就会自动安装相关的 Skill，我们的配置就完成了。</p><h2 id="三-抓取-simon-willison-的全部博客" tabindex="-1">三：抓取 Simon Willison 的全部博客 <a class="header-anchor" href="#三-抓取-simon-willison-的全部博客" aria-label="Permalink to &quot;三：抓取 Simon Willison 的全部博客&quot;">​</a></h2><p><img src="https://pbs.twimg.com/media/HDyHCEMbEAA-W2k?format=jpg&amp;name=large" alt="图像"></p><p>第一步，我先用 Map 功能拿到所有文章 URL：</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用 xcrawl-map 扫描 simonwillison.net，</span></span>
<span class="line"><span>列出所有路径中包含 &quot;/2024/&quot; 或 &quot;/2025/&quot; 或 &quot;/2026/&quot; 的 URL，上限 500 条。</span></span></code></pre></div><p>Map 会扫描站点的 sitemap 和链接结构，返回所有符合条件的 URL，我按年份过滤，只要近三年的文章，实测拿到了 233 篇文章的 URL。</p><p>Simon Willison 真是高产，每年平均 100 篇文章，26 年才三月他已经写了 24 篇文章了。</p><p>接下来是第二步，我开始用 Scrape 逐篇抓取正文：</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用 xcrawl-scrape 批量抓取上面这些 URL 的正文内容，输出为干净的 Markdown 格式。</span></span></code></pre></div><p>Scrape 是精确制导——一个 URL 对应一篇干净的 Markdown，不会抓到导航栏、评论区这些噪声。</p><p>233 篇文章，耗时不到十分钟跑完，每篇都是干净的 Markdown，标题层级、代码块、链接全部保留。</p><p>抓取的同时，因为输出就是 Markdown，我直接让 OpenClaw 把这些文件保存到本地文件夹。然后直接用 Claude Code 打开会话，让 AI 分析这些内容，现在我可以这样问：</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>基于 Simon Willison 的所有文章，总结他对 AI Agent 架构的核心观点，</span></span>
<span class="line"><span>引用具体文章作为出处。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Simon 在过去一年里对哪些 Python 库评价最高？列出库名和他的原话。</span></span></code></pre></div><p>说白了，我现在有了一个「Simon Willison 的大脑副本」，想学什么直接问。</p><h2 id="四-从零构建一个陌生领域的知识库" tabindex="-1">四：从零构建一个陌生领域的知识库 <a class="header-anchor" href="#四-从零构建一个陌生领域的知识库" aria-label="Permalink to &quot;四：从零构建一个陌生领域的知识库&quot;">​</a></h2><p>上面的案例是「我已经知道要学谁」，但更多时候，你面对一个完全陌生的领域，连该看谁的东西都不知道。</p><p>这时候加一步 Search 就行：<strong>先搜关键词找到这个领域最好的内容源，再用 Map 摸清站点结构，最后用 Scrape 把符合你意图的文档全部抓下来。</strong></p><p>比如我想系统学 WebAssembly，先用 Search 找方向：</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用 xcrawl-search 搜索 &quot;WebAssembly practical guide 2025&quot;</span></span>
<span class="line"><span>和 &quot;WASM real world use cases&quot;，英文结果，各返回前 20 条。</span></span></code></pre></div><p>Search 返回结构化的搜索结果——标题、URL、摘要、排名，我从 40 条结果里筛出 5 个高质量站点：核心文档站、深度博客、awesome 列表。</p><p>再用 Map 摸清每个站的结构：</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用 xcrawl-map 列出这个文档站 /docs/ 路径下的所有 URL，上限 200 条。</span></span></code></pre></div><p>对每个筛出来的站点跑一次 Map。有些站只有 20 篇文章，有些有 500 页但大部分是 API reference——Map 帮你在抓之前就做好判断，只选真正有价值的部分。</p><p>最后和上面的步骤一样，用 Scrape 定向抓取：</p><div class="language-plaintext vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">plaintext</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用 xcrawl-scrape 抓取筛选出的这 80 个 URL 的内容，输出 Markdown，</span></span>
<span class="line"><span>保存到本地文件夹。</span></span></code></pre></div><p>最终拿到 80 篇高质量文档，全部是干净 Markdown，直接存到本地做知识库。</p><p><strong>从「我对 WebAssembly 一无所知」到「我有一个 80 篇核心文档的专属知识库」，不到两小时。</strong></p><h2 id="五-几点心得" tabindex="-1">五：几点心得 <a class="header-anchor" href="#五-几点心得" aria-label="Permalink to &quot;五：几点心得&quot;">​</a></h2><p><strong>Map 先行，永远是对的</strong>。不管你多确定要抓什么，先跑一次 Map 看看站点结构，很多站的 URL 规律和你想的不一样，Map 能帮你避免抓一堆垃圾页面。</p><p><strong>Search 的语言设置很重要</strong>。同一个关键词，英文和中文的搜索结果差异巨大，技术领域建议优先搜英文，拿到的源质量普遍更高。</p><p><strong>Markdown 输出是真的省事</strong>。因为输出直接就是 Markdown，我可以让 OpenClaw 直接保存到本地笔记库里，不需要任何格式转换，拿到就能用。</p><p><strong>抓取稳定性比想象中好</strong>。XCrawl 底层会自动轮换 IP，批量抓几百篇文章速度也很快，隐私和安全性都很好，一些开源的方案会遇到一些禁止抓取的的情况，在这里没遇到过。</p><p><strong>关于合规</strong>：XCrawl 内置 robots.txt 检测，只采集公开内容，但选目标站时还是建议手动确认一下抓取政策。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>本质上我这套方法做的事情是：<strong>把互联网上散落的高质量内容，变成你的私人知识库，然后用 AI 帮你消化。</strong></p><p>以前学一个新领域，你得自己找资料、自己读、自己整理笔记。</p><p>现在这个流程变成了：Search 找源 → Map 探路 → Scrape 抓取 → 存到本地 → AI 对话学习。</p><p>对我来说最大的变化是——<strong>学习的瓶颈从「找不到好内容」变成了「怎么问出好问题」。</strong></p><p>这才是 AI 时代学习该有的样子。</p>`,56)]))}const u=s(t,[["render",o]]);export{g as __pageData,u as default};
